import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            char[] A = fs.next().toCharArray();
            char[] B = fs.next().toCharArray();
            int win = 0, loss = 0, draw = 0;
            for (int i = 0; i < N; i++) {
                char a = A[i], b = B[i];
                if (a == b) draw++;
                else if ((a == 'R' && b == 'S') || (a == 'S' && b == 'P') || (a == 'P' && b == 'R')) win++;
                else loss++;
            }
            int diff = win - loss;
            int need = diff >= 1 ? 0 : 1 - diff;
            int ans = 0;
            int useLoss = Math.min(loss, need / 2);
            ans += useLoss;
            need -= useLoss * 2;
            ans += need; // need <= draw
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        String next() throws IOException {
            StringBuilder sb = new StringBuilder();
            int c;
            while ((c = readByte()) != -1 && c <= ' ') {}
            while (c != -1 && c > ' ') { sb.append((char)c); c = readByte(); }
            return sb.toString();
        }
        int nextInt() throws IOException { return Integer.parseInt(next()); }
    }
}

