const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const A = input[idx++];
  const B = input[idx++];
  let win = 0, loss = 0, draw = 0;
  for (let i = 0; i < N; i++) {
    const a = A[i], b = B[i];
    if (a === b) draw++;
    else if ((a === 'R' && b === 'S') || (a === 'S' && b === 'P') || (a === 'P' && b === 'R')) win++;
    else loss++;
  }
  const diff = win - loss;
  let need = diff >= 1 ? 0 : 1 - diff;
  const useLoss = Math.min(loss, Math.floor(need / 2));
  need -= useLoss * 2;
  const ans = useLoss + need; // remaining need covered by draws
  results.push(String(ans));
}
console.log(results.join('\n'));
